import { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";

function ViewApplications() {
  const [apps, setApps] = useState([]);
  const navigate = useNavigate();

  /* =========================
     READ LOGGED-IN USER
  ========================= */
  const loggedUser =
    JSON.parse(localStorage.getItem("loggedInUser")) || {};

  /* =========================
     STRONG ADMIN CHECK (FIX)
  ========================= */
  const isAdmin =
    loggedUser.role?.toLowerCase() === "admin" ||
    loggedUser.username === "admin@test.com" ||
    loggedUser.empId === "admin001";

  /* =========================
     LOAD APPLICATIONS
  ========================= */
  useEffect(() => {
    const stored =
      JSON.parse(localStorage.getItem("applications")) || [];
    setApps(stored);
  }, []);

  /* =========================
     SAFE EMPLOYEE NAME
  ========================= */
  const getEmployeeName = (a) => {
    if (a.employeeName) return a.employeeName;
    if (a.employee) return a.employee;
    return "Unknown";
  };

  return (
    <div style={{ marginTop: "25px" }}>
      <h2>
        {isAdmin ? "Job Applications (Admin)" : "My Job Applications"}
      </h2>

      <table className="designation-table">
        <thead>
          <tr>
            <th>S.No</th>
            <th>Employee</th>
            <th>Email</th>
            <th>Job Title</th>
            <th>Status</th>
            <th>Applied Date</th>
            {isAdmin && <th>Action</th>}
          </tr>
        </thead>

        <tbody>
          {apps.length === 0 ? (
            <tr>
              <td colSpan={isAdmin ? 7 : 6} style={{ textAlign: "center" }}>
                No Applications Found
              </td>
            </tr>
          ) : (
            apps.map((a, i) => (
              <tr key={a.id}>
                <td>{i + 1}</td>
                <td>{getEmployeeName(a)}</td>
                <td>{a.email}</td>
                <td>{a.jobTitle}</td>
                <td>{a.status}</td>
                <td>{a.appliedDate || "--"}</td>

                {/* =========================
                   ADMIN ACTIONS
                ========================= */}
                {isAdmin && (
                  <td style={{ display: "flex", gap: "10px" }}>
                    {/* APPROVED → CREATE OFFER */}
                    {a.status === "Approved" && (
                      <button
                        onClick={() =>
                          navigate(
                            `/dashboard/recruitment/offer-letter/${a.id}`
                          )
                        }
                      >
                        Create Offer
                      </button>
                    )}

                    {/* OFFER SENT → EDIT / VIEW */}
                    {a.status === "OFFER_SENT" && (
                      <>
                        <button
                          onClick={() =>
                            navigate(
                              `/dashboard/recruitment/offer-letter/${a.id}`
                            )
                          }
                        >
                          Edit Offer
                        </button>

                        <button
                          onClick={() =>
                            navigate(
                              `/dashboard/recruitment/offer-preview/${a.id}`
                            )
                          }
                        >
                          View Offer
                        </button>
                      </>
                    )}
                  </td>
                )}
              </tr>
            ))
          )}
        </tbody>
      </table>
    </div>
  );
}

export default ViewApplications;
